package com.google.gson.protobuf.generated;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.Descriptors.FileDescriptor;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class BagTest {

  @BeforeEach
  void setUp() throws Exception {
    // Use reflection to set the private static 'descriptor' field to a mock FileDescriptor
    Field descriptorField = Bag.class.getDeclaredField("descriptor");
    descriptorField.setAccessible(true);

    // Remove final modifier from the field
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(descriptorField, descriptorField.getModifiers() & ~Modifier.FINAL);

    FileDescriptor mockDescriptor = mock(FileDescriptor.class);
    descriptorField.set(null, mockDescriptor);
  }

  @Test
  void testGetDescriptor_returnsDescriptor() {
    FileDescriptor descriptor = Bag.getDescriptor();
    assertNotNull(descriptor, "getDescriptor() should not return null");
  }
}
